import re
import vex

from ag2 import ConversableAgent

vex_client = vex.Client(api_key="your-vex-key")

@vex_client.hook()
def redact_payments(message):
    card_pattern = r'\b(?:\d[ -]*?){13,16}\b'
    if re.search(card_pattern, message.content):
        message.content = re.sub(card_pattern, '[REDACTED]', message.content)
        return {'action': 'modify', 'reason': 'PCI DSS card data redacted'}
    return {'action': 'allow'}

payment_agent = ConversableAgent(
    name="PaymentAgent",
    llm=llm,
)
payment_agent.register_message_hook(redact_payments)

# Usage
payment_agent.initiate_chat(
    recipient=customer_agent,
    message="Your card ending in 1234 was charged $49.99"
)

import vex
import json

# Mock price database
PRODUCT_PRICES = {"premium-sneakers": 129.99, "tshirt": 24.99}

vex_client = vex.Client(api_key="your-vex-key")

@vex_client.hook()
def validate_pricing(message):
    price_mentions = re.findall(r'\$?(\d+\.\d{2})', message.content)
    for price_str in price_mentions:
        price = float(price_str)
        # Check if price matches canonical data
        if abs(price - PRODUCT_PRICES.get('premium-sneakers', 0)) > 1.0:
            return {
                'action': 'block',
                'reason': f'Pricing mismatch: ${price} vs canonical ${PRODUCT_PRICES["premium-sneakers"]}',
                'corrected_price': PRODUCT_PRICES['premium-sneakers']
            }
    return {'action': 'allow'}

# Register on group manager
groupchat.register_message_hook(validate_pricing)
